mapper.update:
UPDATE wms_material
name = #{name}, category_id = #{categoryId}, unit = #{unit}, spec = #{spec}, expiry_warning_days = #{expiryWarningDays}, min_stock = #{minStock}, max_stock = #{maxStock}, image_url = #{imageUrl}, update_time = #{updateTime},
WHERE material_id = #{materialId}

mapper.select:
select count(*) from wms_material m


        AND m.category_id = #{categoryId}


        AND m.name LIKE CONCAT('%', #{keyword}, '%')

SELECT m.*, c.category_name, (SELECT COALESCE(SUM(s.quantity), 0) FROM wms_stock_item s WHERE s.material_id = m.material_id AND s.status = 1) as current_stock FROM wms_material m LEFT JOIN wms_category c ON m.category_id = c.category_id
AND m.category_id = #{categoryId}
AND m.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY m.create_time DESC LIMIT #{limit} OFFSET #{offset}
